"use client";

import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useRouter } from 'next/navigation';
import api from '@/util/api';

// 인터페이스 정의
interface Medication {
    medicationId: number;
    medicineName: string;
    intakeDays: string; // "MON,TUE..." 또는 "EVERYDAY"
}

interface CheckRecord {
    id: number;
    checkDate: string;   // "2026-02-17"
    medicineName: string;
    medicationId: number;
}

export default function MedicationCalendarPage() {
    const router = useRouter();
    const [medications, setMedications] = useState<Medication[]>([]);
    const [records, setRecords] = useState<CheckRecord[]>([]);
    const [currentDate, setCurrentDate] = useState(new Date());
    const [loading, setLoading] = useState(true);
    // 🚀 선택된 날짜 상태 추가
    const [selectedDate, setSelectedDate] = useState<string | null>(null);

    const themeColor = '#4f46e5';

    useEffect(() => {
        const token = localStorage.getItem('token');
        if (!token) {
            router.replace('/authLogin');
            return;
        }
        fetchAllData();
    }, [router]);

    const fetchAllData = async () => {
    try {
        // 🚀 headers와 도메인을 생략하여 훨씬 간결해진 병렬 요청 [cite: 2026-02-18]
        const [medRes, recordRes] = await Promise.all([
            api.get('/api/medication/list'),
            api.get('/api/medication/check/history')
        ]);
        
        // Axios는 응답 데이터가 .data에 담겨 있습니다. [cite: 2026-02-18]
        setMedications(Array.isArray(medRes.data) ? medRes.data : []);
        setRecords(Array.isArray(recordRes.data) ? recordRes.data : []);
    } catch (e: any) {
        console.error("데이터 로딩 실패:", e);
        
        // 세션 만료 시 처리 (필요한 경우)
        if (e.response?.status === 401) {
            alert("세션이 만료되었습니다. 다시 로그인해주세요.");
        }
        
        setMedications([]);
        setRecords([]);
    } finally {
        setLoading(false);
    }
};

    const getDayName = (dayIndex: number) => {
        return ['SUN', 'MON', 'TUE', 'WED', 'THU', 'FRI', 'SAT'][dayIndex];
    };

    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const firstDay = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();

    if (loading) return <div style={{ padding: '150px', textAlign: 'center' }}>로딩 중...</div>;

    return (
        <div style={{ padding: '140px 20px 80px', maxWidth: '800px', margin: '0 auto', fontFamily: 'sans-serif' }}>
            <div style={{ textAlign: 'center', marginBottom: '40px' }}>
                <h1 style={{ fontSize: '28px', fontWeight: '800', color: '#1e293b', marginBottom: '10px' }}>🗓️ 복약 캘린더</h1>
                <p style={{ color: '#64748b' }}>날짜를 클릭하여 상세 복약 내역을 확인하세요.</p>
            </div>

            {/* 달력 컨트롤러 */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px', padding: '0 10px' }}>
                <button 
                    onClick={() => { setCurrentDate(new Date(year, month - 1)); setSelectedDate(null); }}
                    style={{ padding: '10px 15px', border: '1px solid #e2e8f0', borderRadius: '8px', cursor: 'pointer', backgroundColor: '#fff' }}
                >
                    ◀ 이전 달
                </button>
                <h2 style={{ fontSize: '20px', fontWeight: 'bold' }}>{year}년 {month + 1}월</h2>
                <button 
                    onClick={() => { setCurrentDate(new Date(year, month + 1)); setSelectedDate(null); }}
                    style={{ padding: '10px 15px', border: '1px solid #e2e8f0', borderRadius: '8px', cursor: 'pointer', backgroundColor: '#fff' }}
                >
                    다음 달 ▶
                </button>
            </div>

            {/* 요일 표시 */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', marginBottom: '10px', textAlign: 'center', fontWeight: '600', color: '#64748b' }}>
                {['일', '월', '화', '수', '목', '금', '토'].map(d => <div key={d} style={{ padding: '10px' }}>{d}</div>)}
            </div>

            {/* 날짜 그리드 */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '10px' }}>
                {Array.from({ length: firstDay }).map((_, i) => <div key={`empty-${i}`} />)}
                
                {Array.from({ length: daysInMonth }).map((_, i) => {
                    const day = i + 1;
                    const dateObj = new Date(year, month, day);
                    const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                    const dayName = getDayName(dateObj.getDay());

                    const totalToTake = medications.filter(m => 
                        m.intakeDays.includes(dayName) || m.intakeDays === 'EVERYDAY'
                    ).length;

                    const dayRecords = Array.isArray(records) ? records.filter(r => r.checkDate === dateStr) : [];
                    const takenCount = new Set(dayRecords.map(r => r.medicationId)).size;

                    let bgColor = '#fff';
                    let borderColor = selectedDate === dateStr ? themeColor : '#e2e8f0'; // 🚀 선택된 날짜 강조
                    let statusIcon = '';

                    if (totalToTake > 0) {
                        if (takenCount === 0) {
                            bgColor = '#fff';
                        } else if (takenCount < totalToTake) {
                            bgColor = '#fffbeb'; 
                            if(selectedDate !== dateStr) borderColor = '#fbbf24';
                            statusIcon = '⚠️';
                        } else {
                            bgColor = '#f0fdf4'; 
                            if(selectedDate !== dateStr) borderColor = '#22c55e';
                            statusIcon = '✅';
                        }
                    }

                    return (
                        <div 
                            key={day} 
                            onClick={() => setSelectedDate(dateStr)} // 🚀 클릭 시 날짜 선택
                            style={{ 
                                minHeight: '100px', 
                                border: `2px solid ${borderColor}`, 
                                borderRadius: '12px', 
                                padding: '10px', 
                                backgroundColor: bgColor,
                                cursor: 'pointer',
                                transition: 'all 0.2s ease',
                                transform: selectedDate === dateStr ? 'scale(1.02)' : 'none',
                                boxShadow: selectedDate === dateStr ? '0 4px 12px rgba(0,0,0,0.1)' : 'none',
                                display: 'flex',
                                flexDirection: 'column',
                                justifyContent: 'space-between'
                            }}
                        >
                            <div style={{ fontSize: '14px', fontWeight: 'bold', color: selectedDate === dateStr ? themeColor : '#1e293b' }}>{day}</div>
                            
                            <div style={{ textAlign: 'center' }}>
                                {totalToTake > 0 ? (
                                    <div style={{ fontSize: '11px', fontWeight: '700' }}>
                                        {statusIcon} {takenCount}/{totalToTake}
                                    </div>
                                ) : (
                                    <div style={{ fontSize: '10px', color: '#cbd5e1' }}>-</div>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* 🚀 상세 내역 표시 영역 (날짜 클릭 시 나타남) */}
            {selectedDate && (
                <div style={{ 
                    marginTop: '40px', 
                    padding: '25px', 
                    backgroundColor: '#fff', 
                    borderRadius: '16px', 
                    border: '1px solid #e2e8f0',
                    boxShadow: '0 10px 25px -5px rgba(0, 0, 0, 0.1)'
                }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
                        <h3 style={{ margin: 0, fontSize: '20px', color: '#1e293b' }}>📍 {selectedDate} 상세 내역</h3>
                        <button onClick={() => setSelectedDate(null)} style={{ border: 'none', background: 'none', cursor: 'pointer', fontSize: '18px', color: '#94a3b8' }}>✕</button>
                    </div>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                        {(() => {
                            const dayName = getDayName(new Date(selectedDate).getDay());
                            const dayMeds = medications.filter(m => m.intakeDays.includes(dayName) || m.intakeDays === 'EVERYDAY');
                            
                            if (dayMeds.length === 0) return <p style={{ textAlign: 'center', color: '#64748b' }}>이 날은 복약 일정이 없습니다.</p>;

                            return dayMeds.map(m => {
                                const isTaken = records.some(r => r.checkDate === selectedDate && r.medicationId === m.medicationId);
                                return (
                                    <div key={m.medicationId} style={{ 
                                        display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                                        padding: '15px', borderRadius: '10px', border: '1px solid'          ,
                                        backgroundColor: isTaken ? '#f0fdf4' : '#fff1f2',
                                        borderColor: isTaken ? '#22c55e' : '#fda4af'
                                    }}>
                                        <span style={{ fontWeight: '700', color: isTaken ? '#166534' : '#9f1239' }}>{m.medicineName}</span>
                                        <span style={{ fontSize: '14px', fontWeight: '800', color: isTaken ? '#166534' : '#9f1239' }}>
                                            {isTaken ? '✅ 복용 완료' : '❌ 미복용'}
                                        </span>
                                    </div>
                                );
                            });
                        })()}
                    </div>
                </div>
            )}

            {/* 하단 설명(Legend) */}
            <div style={{ marginTop: '40px', padding: '20px', backgroundColor: '#f8fafc', borderRadius: '15px', display: 'flex', justifyContent: 'center', gap: '20px', fontSize: '13px' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <div style={{ width: '12px', height: '12px', backgroundColor: '#fff', border: '1px solid #e2e8f0', borderRadius: '3px' }}></div> 미복용
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <div style={{ width: '12px', height: '12px', backgroundColor: '#fffbeb', border: '1px solid #fbbf24', borderRadius: '3px' }}></div> 일부 복용
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8    px' }}>
                    <div style={{ width: '12px', height: '12px', backgroundColor: '#f0fdf4', border: '1px solid #22c55e', borderRadius: '3px' }}></div> 전체 복용 완료
                </div>
            </div>
        </div>
    );
}